class FixedWindowLimiter:
    def __init__(self, limit, window_seconds):
        self.limit = limit
        self.window_seconds = window_seconds
        self.data = {}

    def allow(self, key, timestamp):
        window_start = (timestamp // self.window_seconds) * self.window_seconds
        if key not in self.data or self.data[key][0] != window_start:
            self.data[key] = [window_start, 0]
        if self.data[key][1] < self.limit:
            self.data[key][1] += 1
            return True
        return False
